import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import BottomNav from './components/BottomNav';
import HomeScreen from './screens/HomeScreen';
import ServicesScreen from './screens/ServicesScreen';
import StoreScreen from './screens/StoreScreen';
import ViralScreen from './screens/ViralScreen';
import AIScreen from './screens/AIScreen';
import GalleryScreen from './screens/GalleryScreen';
import BookingScreen from './screens/BookingScreen';
import CheckoutScreen from './screens/CheckoutScreen';
import AdminPanel from './screens/AdminPanel';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [loading, setLoading] = useState(true);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  const [checkoutItem, setCheckoutItem] = useState<any>(null);
  const [bookingService, setBookingService] = useState<any>(null);

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  const handleAdminTrigger = () => setShowAdminLogin(true);

  if (loading) {
    return (
      <div className="h-screen w-screen green-gradient flex flex-col items-center justify-center">
        <div className="relative">
          <div className="w-24 h-24 rounded-full border-4 border-[#E1B84F]/20 border-t-[#E1B84F] animate-spin"></div>
          <div className="absolute inset-0 flex items-center justify-center font-bold text-2xl text-[#E1B84F]">A</div>
        </div>
        <h1 className="mt-8 text-2xl font-bold tracking-widest text-[#E1B84F]">ANEELA'S</h1>
        <p className="mt-2 text-[#B7C1BC] text-sm animate-pulse italic uppercase tracking-tighter">Perfection in Every Stroke.</p>
      </div>
    );
  }

  if (showAdminLogin && !isAdmin) {
    return <AdminPanel onLogin={() => setIsAdmin(true)} onCancel={() => setShowAdminLogin(false)} />;
  }

  if (isAdmin) {
    return <AdminPanel isFullPanel onLogout={() => { setIsAdmin(false); setShowAdminLogin(false); }} />;
  }

  const renderScreen = () => {
    if (checkoutItem) return <CheckoutScreen item={checkoutItem} onBack={() => setCheckoutItem(null)} />;
    if (bookingService) return <BookingScreen service={bookingService} onBack={() => setBookingService(null)} />;

    switch (activeTab) {
      case 'home': return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} />;
      case 'services': return <ServicesScreen onBook={(s) => setBookingService(s)} />;
      case 'store': return <StoreScreen onBuy={(item) => setCheckoutItem(item)} />;
      case 'viral': return <ViralScreen />;
      case 'ai': return <AIScreen />;
      case 'gallery': return <GalleryScreen />;
      default: return <HomeScreen setActiveTab={setActiveTab} onBook={(s) => setBookingService(s)} />;
    }
  };

  return (
    <div className="min-h-screen green-gradient flex flex-col">
      <Header onAdminTrigger={handleAdminTrigger} />
      <main className="flex-1 pb-24 pt-20 px-4 max-w-lg mx-auto w-full no-scrollbar overflow-y-auto">
        {renderScreen()}
      </main>
      {!checkoutItem && !bookingService && (
        <BottomNav activeTab={activeTab} setActiveTab={setActiveTab} />
      )}
    </div>
  );
};

export default App;

