            <button
              key={t.id}
              onClick={() => setActiveTab(t.id)}
              className={`flex items-center gap-2 px-4 py-2 rounded-full whitespace-nowrap text-[10px] font-bold transition-all ${
                activeTab === t.id ? 'bg-[#E1B84F] text-[#0E3F2A]' : 'bg-[#124C34] text-[#B7C1BC] border border-white/5'
              }`}
            >
              {t.icon} {t.label}
            </button>
          ))}
        </div>

        <div className="space-y-4">
          <h3 className="text-xs font-bold uppercase tracking-[0.2em] text-[#E1B84F]">Manage {activeTab}</h3>

          {/* Actionable List */}
          <div className="space-y-3">
            {[1, 2, 3].map((i) => (
              <div key={i} className="glass-card p-4 rounded-2xl border-white/5 flex items-center justify-between">
                <div className="flex items-center gap-3">
                   <div className="w-10 h-10 rounded-full bg-[#0E3F2A] flex items-center justify-center font-bold text-[10px]">USR</div>
                   <div>
                     <p className="text-xs font-bold">Client Name #{i}</p>
                     <p className="text-[10px] text-[#B7C1BC]">Signature Bridal • 12 Oct</p>
                   </div>
                </div>
                <div className="flex gap-2">
                   <button className="w-8 h-8 rounded-full bg-green-500/20 text-green-500 flex items-center justify-center"><Check size={16} /></button>
                   <button className="w-8 h-8 rounded-full bg-red-500/20 text-red-500 flex items-center justify-center"><X size={16} /></button>
                </div>
              </div>
            ))}
          </div>
        </div>

        <button className="mt-10 w-full bg-[#124C34] border border-[#E1B84F]/50 text-[#E1B84F] font-bold py-4 rounded-2xl flex items-center justify-center gap-2">
           <Video size={18} /> Upload New Transformation Video
        </button>
      </div>
    </div>
  );
};

export default AdminPanel;

